import{c as a,b as p,a as n,F as c,r as l,e as i,i as d,t as r}from"./index-CUwneGr6.js";const o={class:"sub-page phonetics-page"},h={class:"phonetics-rules"},b={__name:"Phonetics",setup(x){const e=i([{title:"见字即读",desc:"田语是表音文字，每个字母对应唯一发音，没有任何不发音字母或例外拼读规则。看到字母即可准确读出，无需查字典。"},{title:"元音和谐",desc:"田语存在元音和谐现象，前元音（e, ê, i, î）和后元音（a, o, ô, u, û）不能在同一词根中共存。这确保了词根内部的语音协调性。"},{title:"尾音规则",desc:"只有 g, l, m, n, r, ŋ 六个字母可作尾音。其中 l 在词尾不发音，g 在词尾为顿音（不爆破），m 为闭口音，n 为前鼻音，r 为卷舌音，ŋ 为后鼻音。"}]);return(g,t)=>(d(),a("div",o,[t[0]||(t[0]=p('<div class="page-header"><h2 class="sub-page-title">语音文字</h2><p class="sub-page-desc">规则1：琳凯蒂亚语共有 41 个字母（26个辅音 + 15个元音），每个字母对应一个固定发音，见字即读，无例外。</p><a href="https://baike.baidu.com/item/%E7%90%B3%E5%87%AF%E8%92%82%E4%BA%9A%E8%AF%AD/66751047" target="_blank" class="baike-link" title="在百度百科查看琳凯蒂亚语">📖 在百度百科查看琳凯蒂亚语 →</a></div><div class="section-card"><h3>语言概述</h3><p>琳凯蒂亚语（Milkēlion / Rincatian，现代语称田语），诞生于2015年前后，历经十余年版本迭代，已从一份初期语音框架发展为具备完整语法体系的人工语言。现代琳凯蒂亚语接近地球语，采用拉丁字母书写，以 O 列元音结尾为典型标志，语序灵活，依赖示词标记句子成分。</p><div class="example-box"><p class="example-text"><strong><span class="rincatian-text">Θi LinVrino θuu parlele ŝi&#39;p swime hâ mide ŝia bulō&#39;a sēgā povide peyoŋ cedāsketē bōnazï ẐaŋNambo&#39;p cēyo.</span></strong></p><p class="example-trans">正是林女士昔日坦言：凭戏水凌波、亲眼邂逅心之所往的寰宇盛景，她相较张先生，愈发倾心盛夏光景。</p></div></div><h3 class="section-heading">辅音字母表（26个辅音）</h3><div class="rule-table-wrap"><table class="rule-table consonant-table"><thead><tr><th>字母</th><th>音标</th><th>转写</th><th>发音要点</th></tr></thead><tbody><tr><td><strong><span class="rincatian-text">M m</span></strong></td><td><span class="phonetic-text">[m] / [m̚]</span></td><td>m</td><td>双唇鼻音；尾音闭口</td></tr><tr><td><strong><span class="rincatian-text">N n</span></strong></td><td><span class="phonetic-text">[n] / [n̚]</span></td><td>n</td><td>舌尖鼻音；尾音前鼻</td></tr><tr><td><strong><span class="rincatian-text">H h</span></strong></td><td><span class="phonetic-text">[x]</span></td><td>h</td><td>清软腭擦音，似汉语&quot;喝&quot;</td></tr><tr><td><strong><span class="rincatian-text">L l</span></strong></td><td><span class="phonetic-text">[l]</span></td><td>l</td><td>齿龈边音；尾音不发音</td></tr><tr><td><strong><span class="rincatian-text">R r</span></strong></td><td><span class="phonetic-text">[ɻ] / [l] / [ɚ]</span></td><td>r</td><td>卷舌近音；尾音卷舌</td></tr><tr><td><strong><span class="rincatian-text">X x</span></strong></td><td><span class="phonetic-text">[ɕ]</span></td><td>x</td><td>龈腭擦音，似汉语&quot;西&quot;</td></tr><tr><td><strong><span class="rincatian-text">Ŝ ŝ</span></strong></td><td><span class="phonetic-text">[ʂ] / [ɕ]</span></td><td>sh</td><td>卷舌擦音，似汉语&quot;是&quot;</td></tr><tr><td><strong><span class="rincatian-text">P p</span></strong></td><td><span class="phonetic-text">[pʰ]</span></td><td>p</td><td>送气清双唇塞音，似汉语&quot;坡&quot;</td></tr><tr><td><strong><span class="rincatian-text">T t</span></strong></td><td><span class="phonetic-text">[tʰ]</span></td><td>t</td><td>送气清齿龈塞音，似汉语&quot;特&quot;</td></tr><tr><td><strong><span class="rincatian-text">K k</span></strong></td><td><span class="phonetic-text">[kʰ]</span></td><td>k</td><td>送气清软腭塞音，似汉语&quot;可&quot;</td></tr><tr><td><strong><span class="rincatian-text">S s</span></strong></td><td><span class="phonetic-text">[s]</span></td><td>s</td><td>清齿龈擦音，似汉语&quot;思&quot;</td></tr><tr><td><strong><span class="rincatian-text">C c</span></strong></td><td><span class="phonetic-text">[tsʰ] / [s]</span></td><td>c</td><td>送气清齿龈塞擦音，似汉语&quot;词&quot;</td></tr><tr><td><strong><span class="rincatian-text">Q q</span></strong></td><td><span class="phonetic-text">[tɕʰ]</span></td><td>q</td><td>送气龈腭塞擦音，似汉语&quot;七&quot;</td></tr><tr><td><strong><span class="rincatian-text">Ĉ ĉ</span></strong></td><td><span class="phonetic-text">[tʂʰ] / [tɕʰ]</span></td><td>ch</td><td>送气卷舌塞擦音，似汉语&quot;吃&quot;</td></tr><tr><td><strong><span class="rincatian-text">B b</span></strong></td><td><span class="phonetic-text">[p]</span></td><td>b</td><td>不送气清双唇塞音，似汉语&quot;波&quot;</td></tr><tr><td><strong><span class="rincatian-text">D d</span></strong></td><td><span class="phonetic-text">[t]</span></td><td>d</td><td>不送气清齿龈塞音，似汉语&quot;的&quot;</td></tr><tr><td><strong><span class="rincatian-text">G g</span></strong></td><td><span class="phonetic-text">[k] / [k̚]</span></td><td>g</td><td>不送气清软腭塞音似汉语&quot;歌&quot;；尾音顿音</td></tr><tr><td><strong><span class="rincatian-text">Θ θ</span></strong></td><td><span class="phonetic-text">[θ]</span></td><td>th</td><td>清齿擦音，似英语 think 的 th</td></tr><tr><td><strong><span class="rincatian-text">Z z</span></strong></td><td><span class="phonetic-text">[ts] / [θ]</span></td><td>z</td><td>不送气清齿龈塞擦音，似汉语&quot;资&quot;</td></tr><tr><td><strong><span class="rincatian-text">J j</span></strong></td><td><span class="phonetic-text">[tɕ]</span></td><td>j</td><td>不送气龈腭塞擦音，似汉语&quot;鸡&quot;</td></tr><tr><td><strong><span class="rincatian-text">Ẑ ẑ</span></strong></td><td><span class="phonetic-text">[tʂ] / [tɕ]</span></td><td>zh</td><td>不送气卷舌塞擦音，似汉语&quot;知&quot;</td></tr><tr><td><strong><span class="rincatian-text">F f</span></strong></td><td><span class="phonetic-text">[f]</span></td><td>f</td><td>清唇齿擦音，似汉语&quot;佛&quot;</td></tr><tr><td><strong><span class="rincatian-text">V v</span></strong></td><td><span class="phonetic-text">[v]</span></td><td>v</td><td>浊唇齿擦音，似英语 very 的 v</td></tr><tr><td><strong><span class="rincatian-text">Y y</span></strong></td><td><span class="phonetic-text">[j]</span></td><td>y</td><td>硬腭近音，半元音，似汉语&quot;衣&quot;</td></tr><tr><td><strong><span class="rincatian-text">W w</span></strong></td><td><span class="phonetic-text">[w]</span></td><td>w</td><td>软腭唇近音，半元音，似汉语&quot;乌&quot;</td></tr><tr><td><strong><span class="rincatian-text">Ŋ ŋ</span></strong></td><td><span class="phonetic-text">[ŋ]</span></td><td>ng</td><td>软腭鼻音，似汉语&quot;能&quot;韵尾</td></tr></tbody></table></div><p class="rule-note">所有辅音字母名称为&quot;辅音发音 + [ɑʊ̯]&quot;（如 b 读 [pɑʊ̯]）。音位变体可自由拼读：ĉ 可读 [tʂʰ] 或 [tɕʰ]，ŝ 可读 [ʂ] 或 [ɕ]，c 可读 [tsʰ] 或 [s]，z 可读 [ts] 或 [θ]，ẑ 可读 [tʂ] 或 [tɕ]，r 可读 [ɻ] 或 [l]。</p><h3 class="section-heading">元音字母表（15个元音）</h3><div class="rule-table-wrap"><table class="rule-table vowel-table"><thead><tr><th>A 列</th><th>E 列</th><th>I 列</th><th>O 列</th><th>U 列</th></tr></thead><tbody><tr><td><strong><span class="rincatian-text">A a</span></strong> <span class="phonetic-text">[ä]</span><br><small>央低不圆唇</small></td><td><strong><span class="rincatian-text">E e</span></strong> <span class="phonetic-text">[e̞]</span><br><small>中前不圆唇</small></td><td><strong><span class="rincatian-text">I i</span></strong> <span class="phonetic-text">[i]</span><br><small>高前不圆唇</small></td><td><strong><span class="rincatian-text">O o</span></strong> <span class="phonetic-text">[ɑʊ̯]</span><br><small>后响复合</small></td><td><strong><span class="rincatian-text">U u</span></strong> <span class="phonetic-text">[u]</span><br><small>高后圆唇</small></td></tr><tr><td><strong><span class="rincatian-text">Ā ā</span></strong> <span class="phonetic-text">[aɪ̯]</span><br><small>ai 前响复合</small></td><td><strong><span class="rincatian-text">Ē ē</span></strong> <span class="phonetic-text">[eɪ̯]</span><br><small>ei 前响复合</small></td><td><strong><span class="rincatian-text">Ï ï</span></strong> <span class="phonetic-text">[z̩]</span><br><small>iz 半辅音</small></td><td><strong><span class="rincatian-text">Ō ō</span></strong> <span class="phonetic-text">[oʊ̯]</span><br><small>ou 后响复合</small></td><td><strong><span class="rincatian-text">Ü ü</span></strong> <span class="phonetic-text">[y]</span><br><small>yu 高前圆唇</small></td></tr><tr><td><strong><span class="rincatian-text">Â â</span></strong> <span class="phonetic-text">[æ]</span><br><small>ae 次低前不圆唇</small></td><td><strong><span class="rincatian-text">Ê ê</span></strong> <span class="phonetic-text">[ɤ]</span><br><small>eh 半高后不圆唇</small></td><td><strong><span class="rincatian-text">Î î</span></strong> <span class="phonetic-text">[ɸ]</span><br><small>iv 半辅音</small></td><td><strong><span class="rincatian-text">Ô ô</span></strong> <span class="phonetic-text">[œ]</span><br><small>oe 半低前圆唇</small></td><td><strong><span class="rincatian-text">Û û</span></strong> <span class="phonetic-text">[o]</span><br><small>uo 半高后圆唇</small></td></tr></tbody></table></div><p class="rule-note">元音按列分为 A、E、I、O、U 五列，每列包含基本元音、长元音/双元音和特殊元音三种变体。除 i、ï、î、u、ü、û 外，其他元音前若有不能合音的元音需读成&quot;[ŋ]+元音发音&quot;。田语以 O 列元音（o, ō, ô）结尾为名词典型标志。</p><div class="section-card"><h3>音节结构（5种合法结构）</h3><div class="rule-table-wrap"><table class="rule-table"><thead><tr><th>序号</th><th>类型</th><th>示例</th><th>音标</th><th>说明</th></tr></thead><tbody><tr><td>①</td><td>纯辅音</td><td><strong><span class="rincatian-text">n</span></strong></td><td><span class="phonetic-text">[n̚]</span></td><td>单独辅音成音节</td></tr><tr><td>②</td><td>纯元音</td><td><strong><span class="rincatian-text">a</span></strong></td><td><span class="phonetic-text">[ä]</span></td><td>单独元音成音节</td></tr><tr><td>③</td><td>辅音 + 元音</td><td><strong><span class="rincatian-text">wi</span></strong></td><td><span class="phonetic-text">[wi]</span></td><td>最常见的音节结构</td></tr><tr><td>④</td><td>元音 + 尾音</td><td><strong><span class="rincatian-text">el</span></strong></td><td><span class="phonetic-text">[e̞]</span></td><td>元音后接不发音尾音</td></tr><tr><td>⑤</td><td>辅音 + 元音 + 尾音</td><td><strong><span class="rincatian-text">lim</span></strong></td><td><span class="phonetic-text">[lim̚]</span></td><td>完整闭音节结构</td></tr></tbody></table></div><p class="rule-note">每个字母（无论是元音还是辅音）在书写上是一个独立单位，在发音上可构成一个独立音节。例如 <span class="rincatian-text">debtooin</span> 的音节划分为 <span class="rincatian-text">de + b + to + o + in</span>，其中 b 依结构①独立构成纯辅音音节。</p></div><div class="section-card"><h3>尾音系统（6个可作尾音的字母）</h3><div class="rule-table-wrap"><table class="rule-table"><thead><tr><th>序号</th><th>尾音字母</th><th>音标</th><th>类型</th><th>示例</th></tr></thead><tbody><tr><td>①</td><td><strong><span class="rincatian-text">g</span></strong></td><td><span class="phonetic-text">[k̚]</span></td><td>顿音（不爆破）</td><td><span class="rincatian-text">pag</span> <span class="phonetic-text">[pʰäk̚]</span></td></tr><tr><td>②</td><td><strong><span class="rincatian-text">l</span></strong></td><td><span class="phonetic-text">—</span></td><td>不发音</td><td><span class="rincatian-text">bel</span> <span class="phonetic-text">[pe̞]</span></td></tr><tr><td>③</td><td><strong><span class="rincatian-text">m</span></strong></td><td><span class="phonetic-text">[m̚]</span></td><td>闭口音</td><td><span class="rincatian-text">nim</span> <span class="phonetic-text">[nim̚]</span></td></tr><tr><td>④</td><td><strong><span class="rincatian-text">n</span></strong></td><td><span class="phonetic-text">[n̚]</span></td><td>前鼻音</td><td><span class="rincatian-text">in</span> <span class="phonetic-text">[in̚]</span></td></tr><tr><td>⑤</td><td><strong><span class="rincatian-text">r</span></strong></td><td><span class="phonetic-text">[ɚ]</span></td><td>卷舌音</td><td><span class="rincatian-text">per</span> <span class="phonetic-text">[pʰe̞ɚ]</span></td></tr><tr><td>⑥</td><td><strong><span class="rincatian-text">ŋ</span></strong></td><td><span class="phonetic-text">[ŋ]</span></td><td>后鼻音</td><td><span class="rincatian-text">caŋ</span> <span class="phonetic-text">[tsʰäŋ]</span></td></tr></tbody></table></div><p class="rule-note">注意：尾音 <span class="rincatian-text">l</span> 在词尾时不发音，仅标记前面元音的发音方式。词尾不允许辅音连缀，必须以元音或尾音结尾。</p></div><h3 class="section-heading">发音规则</h3>',11)),n("div",h,[(d(!0),a(c,null,l(e.value,s=>(d(),a("div",{class:"rule-card",key:s.title},[n("h4",null,r(s.title),1),n("p",null,r(s.desc),1)]))),128))]),t[1]||(t[1]=p('<div class="section-card"><h3>发音对比示例</h3><div class="rule-table-wrap"><table class="rule-table"><thead><tr><th>田语</th><th>发音</th><th>释义</th><th>音节分析</th></tr></thead><tbody><tr><td><span class="rincatian-text">libo</span></td><td><span class="phonetic-text">[li bo]</span></td><td>书</td><td><span class="rincatian-text">li</span>（辅+元）+ <span class="rincatian-text">bo</span>（辅+元）</td></tr><tr><td><span class="rincatian-text">caŋ</span></td><td><span class="phonetic-text">[tsʰäŋ]</span></td><td>全部</td><td><span class="rincatian-text">caŋ</span>（辅+元+尾音 ŋ）</td></tr><tr><td><span class="rincatian-text">bel-</span></td><td><span class="phonetic-text">[pe̞]</span></td><td>美（词根）</td><td><span class="rincatian-text">bel-</span>（辅+元+尾音 l，l不发音）</td></tr><tr><td><span class="rincatian-text">nim</span></td><td><span class="phonetic-text">[nim̚]</span></td><td>二</td><td><span class="rincatian-text">nim</span>（辅+元+尾音 m，闭口）</td></tr><tr><td><span class="rincatian-text">pag-</span></td><td><span class="phonetic-text">[pʰäk̚]</span></td><td>打（词根）</td><td><span class="rincatian-text">pag-</span>（辅+元+尾音 g，顿音）</td></tr><tr><td><span class="rincatian-text">per-</span></td><td><span class="phonetic-text">[pʰe̞ɚ]</span></td><td>（词根）</td><td><span class="rincatian-text">per-</span>（辅+元+尾音 r，卷舌）</td></tr><tr><td><span class="rincatian-text">in</span></td><td><span class="phonetic-text">[in̚]</span></td><td>人</td><td><span class="rincatian-text">in</span>（元+尾音 n，前鼻音）</td></tr><tr><td><span class="rincatian-text">ŝelo</span></td><td><span class="phonetic-text">[ʂe lo]</span></td><td>贝壳</td><td><span class="rincatian-text">ŝe</span>（辅+元）+ <span class="rincatian-text">lo</span>（辅+元）</td></tr></tbody></table></div></div>',1))]))}};export{b as default};
